package io.github.weiyongzenqi.unuplayer.domain

/**
 * 拼音首字母排序支持。
 * 数据由 pypinyin 生成, 覆盖 Unicode CJK 基本区 U+4E00..U+9FFF(20992 字)。
 * 纯 Kotlin 无 JVM 依赖, commonMain 可用, 桌面/iOS 零成本扩展。
 * 多音字取 pypinyin 默认首个读音, 首字母模式下影响极小。
 */
internal object PinyinSorter {
    private const val MIN = 0x4E00
    private const val MAX = 0x9FFF

    private const val TABLE = "*DQDFMSD*****XQBPFDWO**WHLYPCBJCC*DMBZPBZZ*****Z*W***Z****S*****L*******SL**Z****LGTM****GD*********************ATN**HBLTDZLATMMBJ*LX"

    /** [c] 的拼音首字母大写; 非中文或无拼音返回 null。 */
    fun initial(c: Char): Char? {
        val cp = c.code
        if (cp < MIN || cp > MAX) return null
        val ch = TABLE[cp - MIN]
        return if (ch == '*') null else ch
    }

    /** 排序键: 中文转首字母大写, 非中文转小写原字符, 拼成字符串用于比较。 */
    fun sortKey(s: String): String {
        val sb = StringBuilder(s.length)
        for (c in s) {
            val ini = initial(c)
            if (ini != null) sb.append(ini) else sb.append(c.lowercaseChar())
        }
        return sb.toString()
    }
}
